INSERT INTO monkey (name, code, gender, age, health_status, habitat, personality, story, image_url, is_adopted) VALUES
('毛毛', 'GM-2021-001', '雄性', 5, '健康', '四川卧龙国家级自然保护区', '活泼好动，喜欢攀爬高处，经常在猴群中充当"小队长"角色', '毛毛出生于2020年春天，是猴群中最活跃的年轻个体。它特别喜欢在清晨的阳光下梳理毛发，经常与小伙伴追逐嬉戏。保育员说它是最聪明的小猴之一，学习新技能特别快。', 'https://images.unsplash.com/photo-1540573133985-87b6da6d54a9?w=600', false),
('金妞', 'GM-2020-002', '雌性', 6, '健康', '陕西佛坪国家级自然保护区', '温柔文静，喜欢照顾小猴，是猴群中的"好妈妈"', '金妞是一位非常有母爱的金丝猴，她经常帮助其他母猴照顾幼崽。她特别喜欢吃嫩竹叶，每到春天就显得格外精神。她的毛发在阳光下会呈现出美丽的金色光泽，是保护区的明星。', 'https://images.unsplash.com/photo-1564349683136-77e08dba1ef7?w=600', false),
('豆豆', 'GM-2022-003', '雄性', 3, '健康', '湖北神农架国家级自然保护区', '好奇心强，喜欢探索新事物，经常第一个尝试新食物', '豆豆是最年轻的成年猴，对周围的一切都充满好奇。保育员每次放置新的丰容玩具，它总是第一个冲上去研究。虽然年轻，但它已经开始展现出领导才能，经常组织小猴子们玩耍。', 'https://images.unsplash.com/photo-1591561954557-26941169b49e?w=600', false),
('银背', 'GM-2015-004', '雄性', 12, '良好', '四川卧龙国家级自然保护区', '沉稳威严，是猴群的猴王，保护欲极强', '银背是猴群中最年长的雄性，担任猴王已有5年时间。它的背部毛发已开始泛白，因此得名。它非常负责，总是第一个发现危险，最后一个进食。尽管威严，但它对幼猴十分温柔。', 'https://images.unsplash.com/photo-1535930749574-1399327ce78f?w=600', false),
('小花', 'GM-2023-005', '雌性', 2, '健康', '甘肃白水江国家级自然保护区', '胆小敏感，喜欢躲在妈妈怀里，爱吃花蜜', '小花是猴群中最小的成员，刚满2岁不久。她特别黏妈妈，走到哪跟到哪。虽然胆小，但她对花蜜情有独钟，每当花开季节，她会小心翼翼地品尝每一朵花的甜蜜。', 'https://images.unsplash.com/photo-1607006344380-b6775a0824a7?w=600', false),
('阿山', 'GM-2019-006', '雄性', 7, '健康', '陕西佛坪国家级自然保护区', '憨厚老实，喜欢独自发呆，食量惊人', '阿山是猴群中的"老实人"，不争不抢，总是最后一个取食。它喜欢独自坐在高高的树枝上眺望远方，似乎在思考猴生。它的体型是猴群中最大的，保育员开玩笑说它是"佛系吃货"。', 'https://images.unsplash.com/photo-1550745165-9bc0b252726f?w=600', false);
INSERT INTO adoption_tier (name, code, price, duration_months, description, benefits, badge_image_url, sort_order, is_active) VALUES
('爱心守护', 'TIER_BASIC', 99.00, 1, '每月捐赠99元，为一只川金丝猴提供基础食物和照料', '1. 专属电子认养证书\n2. 每月收到猴子生活报告\n3. "爱心守护"虚拟徽章\n4. 年度公益答谢会参与资格', '/badges/tier-basic.png', 1, true),
('成长伙伴', 'TIER_STANDARD', 299.00, 3, '季度捐赠299元，陪伴川金丝猴健康成长', '1. 精美电子认养证书（含专属编号）\n2. 每月猴子生活视频\n3. "成长伙伴"虚拟徽章\n4. 可申请命名权（需审核）\n5. 园区线下参观优先预约', '/badges/tier-standard.png', 2, true),
('守护大使', 'TIER_PREMIUM', 999.00, 12, '年度捐赠999元，成为川金丝猴的官方守护大使', '1. 精装版PDF认养证书\n2. 每季度猴子专属生活影像记录\n3. "守护大使"尊贵虚拟徽章\n4. 专属命名权（永久）\n5. 受邀参加年度保护论坛\n6. 纪念品礼包一份\n7. 园区VIP参观通道', '/badges/tier-premium.png', 3, true),
('终身守护者', 'TIER_LIFETIME', 9999.00, 120, '一次性捐赠9999元，成为川金丝猴的终身守护者', '1. 终身荣誉认养证书\n2. 专属影像纪录片\n3. "终身守护者"至尊徽章\n4. 永久命名权\n5. 特邀加入保护专家委员会\n6. 终身免费参观园区\n7. 定制纪念品\n8. 参与年度放归活动（如符合）', '/badges/tier-lifetime.png', 4, true);
